func storeToTree(store *gossip.StateStore) *merkle.Tree {
	tree := merkle.NewTree()
	entries := make(map[string][]byte)
	for key := range store.Digest().Entries {
		e, ok := store.GetEntry(key)
		if ok {
			entries[key] = encodeMerkleEntry(e)
		}
	}
	tree.PutBatch(entries)
	return tree
}

func encodeMerkleEntry(e *gossip.StateEntry) []byte {
	buf := make([]byte, 9+len(e.Value))
	binary.BigEndian.PutUint64(buf[:8], e.Version)
	if e.Tombstone {
		buf[8] = 1
	}
	copy(buf[9:], e.Value)
	return buf
}

func (ns *NetworkSim) peerList() []string {
	list := make([]string, 0, len(ns.nodes))
	for id := range ns.nodes {
		list = append(list, id)
	}
	sort.Strings(list)
	return list
}

// Converged checks if all nodes have the same state hash.
func (ns *NetworkSim) Converged() bool {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	var firstHash [32]byte
	first := true
	for _, store := range ns.stores {
		h := store.Hash()
		if first {
			firstHash = h
			first = false
		} else if h != firstHash {
			return false
		}
	}
	return true
}

// GetStore returns a node's state store.
func (ns *NetworkSim) GetStore(nodeID string) *gossip.StateStore {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	return ns.stores[nodeID]
}

// Clock returns the current simulation time.
func (ns *NetworkSim) Clock() uint64 {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	return ns.clock
}

// recordEvent appends an event, evicting the oldest half when the buffer is full.
func (ns *NetworkSim) recordEvent(e Event) {
	if len(ns.events) >= maxEventLog {
		n := copy(ns.events, ns.events[len(ns.events)/2:])
		ns.events = ns.events[:n]
	}
	ns.events = append(ns.events, e)
}

// EventLog returns all recorded events.
func (ns *NetworkSim) EventLog() []Event {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	log := make([]Event, len(ns.events))
	copy(log, ns.events)
	return log
}

// NodeCount returns the number of active nodes.
func (ns *NetworkSim) NodeCount() int {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	return len(ns.nodes)
}

