}

func runMerkleUntilConverged(t *testing.T, ns *NetworkSim, rounds int) {
	t.Helper()
	for i := 0; i < rounds; i++ {
		ns.RunMerkleSyncRound()
		if ns.Converged() {
			return
		}
	}
	t.Fatalf("cluster did not converge after %d merkle rounds", rounds)
}

func assertDeletedOnAllNodes(t *testing.T, ns *NetworkSim, nodeIDs []string, key string, version uint64) {
	t.Helper()
	for _, nodeID := range nodeIDs {
		store := ns.GetStore(nodeID)
		if _, ok := store.Get(key); ok {
			t.Fatalf("%s should not return deleted key %q", nodeID, key)
		}
		entry, ok := store.GetEntry(key)
		if !ok {
			t.Fatalf("%s missing tombstone for %q", nodeID, key)
		}
		if !entry.Tombstone {
			t.Fatalf("%s has live entry for %q", nodeID, key)
		}
		if entry.Version != version {
			t.Fatalf("%s has tombstone version %d for %q, want %d", nodeID, entry.Version, key, version)
		}
	}
}

